// Ported from Input Routing.txt — ChangeInputLR left output
const blustream = global.get('blustream');
const devices = global.get('devices');
const modeState = global.get('modeState');

const inputNum = msg.payload.inputNum;
const { acm, outputs } = devices.blustream;

(async () => {
    try {
        console.log(`[changeInputLeft] Routing left projector → input ${inputNum}`);
        await blustream.switchOutputToInput(acm.ip, acm.port, outputs.projectorLeft.id, String(inputNum));
        modeState.inputSelection.left = inputNum;
        console.log('[changeInputLeft] Done');
        msg.payload = { success: true, projector: 'left', inputNum };
        node.send(msg);
    } catch (err) {
        node.error('[changeInputLeft] ' + err.message, msg);
    }
})();

return null;

