// Ported from Input Routing.txt — ChangeInputRR (rear output, special case)
// Rear projector must be on HDMI1 (Blustream feed) for matrix routing to work.
// Blustream switch is always sent regardless of projector source state —
// mirrors original Lua which calls the Blustream command in both if/else branches.
const projector = global.get('projector');
const blustream = global.get('blustream');
const devices = global.get('devices');
const modeState = global.get('modeState');

const inputNum = msg.payload.inputNum;
const { acm, outputs } = devices.blustream;
const rearIp = devices.projectors.rear.ip;

(async () => {
    try {
        console.log('[changeInputRear] Checking rear projector current source');
        const current = await projector.getCurrentInput(rearIp);
        console.log(`[changeInputRear] Current source: ${current}`);

        if (current !== projector.SOURCE_CODES.HDMI1) {
            console.log('[changeInputRear] Switching rear projector to HDMI1 (Blustream feed)');
            await projector.setInput(rearIp, projector.SOURCE_CODES.HDMI1);
        }

        console.log(`[changeInputRear] Routing Blustream rear output → input ${inputNum}`);
        await blustream.switchOutputToInput(acm.ip, acm.port, outputs.projectorRear.id, String(inputNum));

        modeState.inputSelection.rear = inputNum;
        modeState.rearCurrentInput = projector.SOURCE_CODES.HDMI1;
        console.log('[changeInputRear] Done');
        msg.payload = { success: true, projector: 'rear', inputNum };
        node.send(msg);
    } catch (err) {
        node.error('[changeInputRear] ' + err.message, msg);
    }
})();

return null;

// Ported from Input Routing.txt — SetAllInputs
// Calls changeInputLeft → changeInputRight → changeInputRear logic in sequence.
// Rear uses the same special-case source check as changeInputRear.
const projector = global.get('projector');
const blustream = global.get('blustream');
const devices = global.get('devices');
const modeState = global.get('modeState');

const inputNum = msg.payload.inputNum;
const { acm, outputs } = devices.blustream;
const rearIp = devices.projectors.rear.ip;

(async () => {
    try {
        console.log(`[setAllProjectorInputs] Routing all projectors → input ${inputNum}`);

        // Left
        await blustream.switchOutputToInput(acm.ip, acm.port, outputs.projectorLeft.id, String(inputNum));
        modeState.inputSelection.left = inputNum;
        console.log('[setAllProjectorInputs] Left done');

        // Right
        await blustream.switchOutputToInput(acm.ip, acm.port, outputs.projectorRight.id, String(inputNum));
        modeState.inputSelection.right = inputNum;
        console.log('[setAllProjectorInputs] Right done');

        // Rear — same special-case source check as changeInputRear
        const current = await projector.getCurrentInput(rearIp);
        if (current !== projector.SOURCE_CODES.HDMI1) {
            await projector.setInput(rearIp, projector.SOURCE_CODES.HDMI1);
        }
        await blustream.switchOutputToInput(acm.ip, acm.port, outputs.projectorRear.id, String(inputNum));
        modeState.inputSelection.rear = inputNum;
        modeState.rearCurrentInput = projector.SOURCE_CODES.HDMI1;
        console.log('[setAllProjectorInputs] Rear done');

        console.log('[setAllProjectorInputs] All done');
        msg.payload = { success: true, inputNum };
        node.send(msg);
    } catch (err) {
        node.error('[setAllProjectorInputs] ' + err.message, msg);
    }
})();

return null;

// Ported from Input Routing.txt — Classroom Mode HDMI direct-patch (teacher passthrough)
// Sets rear projector to its own HDMI2 input, bypassing the Blustream matrix entirely.
// No Blustream command is sent — this is a direct projector source switch.
const projector = global.get('projector');
const devices = global.get('devices');
const modeState = global.get('modeState');

const rearIp = devices.projectors.rear.ip;

(async () => {
    try {
        console.log('[setRearToDirectHDMI2] Switching rear projector to direct HDMI2 (teacher passthrough)');
        await projector.setInput(rearIp, projector.SOURCE_CODES.HDMI2);
        modeState.rearCurrentInput = 'HDMI2';
        console.log('[setRearToDirectHDMI2] Done');
        msg.payload = { success: true, source: 'HDMI2' };
        node.send(msg);
    } catch (err) {
        node.error('[setRearToDirectHDMI2] ' + err.message, msg);
    }
})();

return null;
